// Forward the webhook payload to Next.js internal API
const webhookData = $input.all()[0].json;

try {
  const response = await fetch('http://host.docker.internal:3000/api/webhooks/internal/process-message', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Internal-Secret': 'moovchat-internal-secret-123'
    },
    body: JSON.stringify(webhookData)
  });

  const result = await response.json();
  return [{ json: { status: response.status, ...result } }];
} catch (error) {
  return [{ json: { error: error.message } }];
}
